export function getActivitiesForCategory(categoryId: string): ActivityRecord[] {
  return CATEGORY_ACTIVITIES.filter((a) => a.categoryId === categoryId);
}

export function getActivityBySlug(slug: string): ActivityRecord | undefined {
  return CATEGORY_ACTIVITIES.find((a) => a.slug === slug);
}

export function activityPath(slug: string) {
  return `/activities/${slug}`;
}
